module mux4to1_active_high (
  input [3:0] data_in_0,
  input [3:0] in1,
  input [3:0] in2,
  input [3:0] in3,
  input [1:0] sel,
  input en,
  output reg [3:0] out
);

  always @(*) begin
    if (en) begin
      case (sel)
        2'b00: out = data_in_0;
        2'b01: out = in1;
        2'b10: out = in2;
        2'b11: out = in3;
        default: out = 4'b0000;
      endcase
    end else begin
      out = 4'b0000;
    end
  end

endmodule
